export function Card({ children }) {
  return <div className="border rounded p-4 bg-white shadow">{children}</div>;
}
export function CardHeader({ children }) { return <div className="mb-2 font-bold">{children}</div>; }
export function CardTitle({ children }) { return <h2 className="text-lg font-semibold">{children}</h2>; }
export function CardContent({ children }) { return <div>{children}</div>; }
